local LxBaseHandler = require("LApp.handler.LxBaseHandler")
---@class LxActivityHandler:LxBaseHandler
local LxActivityHandler = classX("LxActivityHandler", LxBaseHandler)

function LxActivityHandler:Initialize()
    LxBaseHandler.Initialize(self)
end

function LxActivityHandler:Dispose()
    LxBaseHandler.Dispose(self)
end

function LxActivityHandler:ClearHandler()
    LxBaseHandler.ClearHandler(self)
end

function LxActivityHandler:InitOk()

end

-- 完成登录后
function LxActivityHandler:LoginOk()

end

-- 初始化协议
function LxActivityHandler:InitHandler()
    self:AddMsgHandler(LxProtoIds.ListActivityResp, self.OnListActivityResp, self)
    self:AddMsgHandler(LxProtoIds.UpdateActivityResp, self.OnUpdateActivityResp, self)
    self:AddMsgHandler(LxProtoIds.UpdatePageResp, self.OnUpdatePageResp, self)
    self:AddMsgHandler(LxProtoIds.ReceiveGoalEntryResp, self.OnReceiveGoalEntryResp, self)
    self:AddMsgHandler(LxProtoIds.MarketBuyResp, self.OnMarketBuyResp, self)
    self:AddMsgHandler(LxProtoIds.ReceiveMultiGoalEntryResp, self.OnReceiveMultiGoalEntryResp, self)
    self:AddMsgHandler(LxProtoIds.CustomizedOperationResp, self.OnCustomizedOperationResp, self)
    self:AddMsgHandler(LxProtoIds.ActivityDictionaryResp, self.OnActivityDictionaryResp, self)
end

-- 登陆成功下发
function LxActivityHandler:OnListActivityResp(pb)
    local LxActivityModule =  ModuleCenter.Activity
    for k, v in ipairs(pb.activityList) do
        LxActivityModule:SetData(v.refId, v)
    end
    FireEvent(EventNames.ACTIVITY_ALL_RETURN)
end

-- 主动推送活动增、删、改
function LxActivityHandler:OnUpdateActivityResp(pb)
    local LxActivityModule =  ModuleCenter.Activity
    local refIdMap = {}
    for k, v in ipairs(pb.updateList) do
        LxActivityModule:SetData(v.refId, v)
        refIdMap[v.refId] = v.refId
    end
    for k, refId in ipairs(pb.removeList) do
        LxActivityModule:SetData(refId, nil)
        refIdMap[refId] = refId
    end
    FireEvent(EventNames.ACTIVITY_UPDATA_LIST, refIdMap)
end

-- 主动推送活动分页数据变化
function LxActivityHandler:OnUpdatePageResp(pb)
    local LxActivityModule =  ModuleCenter.Activity
    local refIdMap = {}
    LxActivityModule:UpdateEntryList(pb.activityId, pb.pageId, pb.entryList)

    refIdMap[pb.activityId] = pb.activityId

    FireEvent(EventNames.ACTIVITY_UPDATA_LIST, refIdMap)
end

-- 领取目标条目奖励 请求
function LxActivityHandler:ReceiveGoalEntryReq(activityId, pageId, entryIdList)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.ReceiveGoalEntryReq)
    proto.activityId = activityId
    proto.pageId = pageId

    for k, v in ipairs(entryIdList) do
        table.insert(proto.entryId, v)
    end
    SendMessage(LxProtoIds.ReceiveGoalEntryReq, proto)
end

-- 领取目标条目奖励 返回
function LxActivityHandler:OnReceiveGoalEntryResp(pb)
    local LxActivityModule =  ModuleCenter.Activity
    local refIdMap = {}
    LxActivityModule:UpdateEntryList(pb.activityId, pb.pageId, pb.entryList)

    refIdMap[pb.activityId] = pb.activityId

    FireEvent(EventNames.ACTIVITY_UPDATA_LIST, refIdMap, true)

    local list = {}
    for k, v in ipairs(pb.rewardInfo.heroes or {}) do
        if not v.autoResole then
            table.insert(list, v)
        end
    end
    if #list > 0 then
        local num = ModuleCenter.Hero:GetHeroCount(list[1].refId)
        if num == 1 then
            --ModuleCenter.Debug.WriteFileByLuaData(list, "HeroCallHighQuality")
            local data = {
                showHeroList = list,
                callBackFunc = function()
                    FireEvent(EventNames.RET_SET_UI_MOLEL)
                    FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.Activity, pb.rewardInfo)
                end,
            }
            ShowPanel(UiNames.HeroCallHighQuality, data)
            return
        end
    end
    FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.Activity, pb.rewardInfo)
end

-- 购买商品/特权分页的商品条目 请求
function LxActivityHandler:MarketBuyReq(activityId, pageId, entryId, count)
    local proto      = LxProtoHelper.CreateProto(LxProtoIds.MarketBuyReq)
    proto.activityId = activityId
    proto.pageId     = pageId
    proto.entryId    = entryId
    proto.count      = count
    SendMessage(LxProtoIds.MarketBuyReq, proto)
end

-- 购买商品/特权分页的商品条目 返回
function LxActivityHandler:OnMarketBuyResp(pb)
    ClosePanel(UiNames.ActivityComFightBuy)

    local LxActivityModule =  ModuleCenter.Activity
    local refIdMap = {}
    LxActivityModule:UpdateEntryList(pb.activityId, pb.pageId, {pb.entry})
    refIdMap[pb.activityId] = pb.activityId
    FireEvent(EventNames.ACTIVITY_UPDATA_LIST, refIdMap, true)

    FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.Activity, pb.rewardInfo)
end

-- 合并领取多个分页的目标条目奖励 请求
function LxActivityHandler:ReceiveMultiGoalEntryReq(activityId, list)
    local proto      = LxProtoHelper.CreateProto(LxProtoIds.ReceiveMultiGoalEntryReq)
    proto.activityId = activityId
    for k, v in ipairs(list) do
        local obj = LxProtoHelper.CreateProto(LxProtoIds.MultiGoalObj)
        obj.pageId = v.pageRefId
        for _, entryRefId in ipairs(v.entryRefIdList) do
            table.insert(obj.entryId, entryRefId)
        end
        table.insert(proto.goalList, obj)
    end
    SendMessage(LxProtoIds.ReceiveMultiGoalEntryReq, proto)
end

-- 合并领取多个分页的目标条目奖励 返回
function LxActivityHandler:OnReceiveMultiGoalEntryResp(pb)
    local refIdMap = {[pb.activityId] = pb.activityId}
    FireEvent(EventNames.ACTIVITY_UPDATA_LIST, refIdMap, true)
    FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.Activity, pb.rewardInfo)
end
---动态操作请求
---@param activityId 活动ID
---@param pageId 分页ID
---@param entryId 条目ID
---@param args 特殊操作参数封装
function LxActivityHandler:CustomizedOperationReq(activityId,pageId,entryId,args)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.CustomizedOperationReq)
    proto.activityId = activityId
    proto.pageId = pageId
    proto.entryId = entryId
    local a = proto.args
    a.type = args.type
    a.params = args.params
    SendMessage(LxProtoIds.CustomizedOperationReq,proto)
end

function LxActivityHandler:OnCustomizedOperationResp(pb)
    if pb.page ~= nil then
        ModuleCenter.Activity:UpdatePages(pb.activityId, pb.page)

        local refIdMap = {}
        refIdMap[pb.activityId] = pb.activityId
        FireEvent(EventNames.ACTIVITY_UPDATA_LIST, refIdMap)
    end

    FireEvent(EventNames.ACTIVITY_CUSTOM_UPDATE)
    FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.BuildReward, pb.rewardInfo)
end

function LxActivityHandler:OnActivityDictionaryResp(pb)
    local names = CJSON.decode(pb.dictionary)
    ModuleCenter.Activity:SetActivityLngNameMaps(names)
end

return LxActivityHandler